def can_transform(string1, string2):
    # If the lengths are not equal, transformation is not possible
    if len(string1) != len(string2):
        return False

    # Create mappings from characters in string1 to string2 and vice versa
    map1 = {}
    map2 = {}

    for char1, char2 in zip(string1, string2):
        # Check if there's a conflicting mapping
        if (char1 in map1 and map1[char1] != char2) or (char2 in map2 and map2[char2] != char1):
            return False
        # Create the mapping
        map1[char1] = char2
        map2[char2] = char1

    return True

