def alphabet_war(fight):
    # Define the power of each letter for both sides
    left_side = {'w': 4, 'p': 3, 'b': 2, 's': 1}
    right_side = {'m': 4, 'q': 3, 'd': 2, 'z': 1}

    # Convert the fight string into a list for easier manipulation
    fight_list = list(fight)

    # Iterate over the fight list to simulate the bomb effect
    for i in range(len(fight_list)):
        if fight_list[i] == '*':
            # Bomb affects the current position and adjacent positions
            if i > 0:
                fight_list[i - 1] = '_'
            if i < len(fight_list) - 1:
                fight_list[i + 1] = '_'
            fight_list[i] = '_'

    # Calculate the total power for each side
    left_power = sum(left_side.get(char, 0) for char in fight_list)
    right_power = sum(right_side.get(char, 0) for char in fight_list)

    # Determine the winner
    if left_power > right_power:
        return "Left side wins!"
    elif right_power > left_power:
        return "Right side wins!"
    else:
        return "Let's fight again!"

