def transform_string(s):
    vowels = {'a', 'e', 'i', 'o', 'u'}
    exceptions = {'c': -1, 'o': -1, 'd': -3, 'e': -4}
    result = []

    for char in s:
        if char in exceptions:
            new_char = chr((ord(char) - ord('a') + exceptions[char]) % 26 + ord('a'))
            if new_char in exceptions:
                new_char = char
            result.append(new_char)
        elif char in vowels:
            new_char = chr((ord(char) - ord('a') - 5) % 26 + ord('a'))
            if new_char in exceptions:
                new_char = char
            result.append(new_char)
        else:
            new_char = chr((ord(char) - ord('a') + 9) % 26 + ord('a'))
            if new_char in exceptions:
                new_char = char
            result.append(new_char)

    return ''.join(result)

