def transform_sentence(sentence):
    words = sentence.split()
    transformed_words = []

    for word in words:
        # Check for punctuation at the end of the word
        punctuation = ''
        if not word[-1].isalnum():
            punctuation = word[-1]
            word = word[:-1]

        # Apply transformations based on the rules
        if len(word) > 6 or word.lower().count('t') >= 2:
            transformed_word = word[::-1] + punctuation
        elif len(word) == 2 or (punctuation == ',' and len(word) > 0):
            transformed_word = word.upper() + punctuation
        elif len(word) == 1:
            transformed_word = '0' + punctuation
        else:
            transformed_word = word + punctuation

        transformed_words.append(transformed_word)

    return ' '.join(transformed_words)

