def can_be_increasing(sequence):
    def is_strictly_increasing(seq):
        return all(seq[i] < seq[i + 1] for i in range(len(seq) - 1))

    for i in range(len(sequence)):
        # Create a new sequence by removing the i-th element
        new_sequence = sequence[:i] + sequence[i+1:]
        # Check if the new sequence is strictly increasing
        if is_strictly_increasing(new_sequence):
            return True

    return False

