def remove_element_to_maximize_product(arr):
    # Calculate the product of all elements in the array
    total_product = 1
    for num in arr:
        total_product *= num

    # Initialize variables to track the maximum product and the element to remove
    max_product = float('-inf')
    element_to_remove = None

    # Iterate over each element in the array
    for num in arr:
        # Calculate the product if the current element is removed
        if num != 0:
            current_product = total_product // num
        else:
            # If the element is zero, calculate the product of the rest of the array
            current_product = 1
            for other_num in arr:
                if other_num != num:
                    current_product *= other_num

        # Update the maximum product and the element to remove if necessary
        if current_product > max_product:
            max_product = current_product
            element_to_remove = num
        elif current_product == max_product:
            # If the current product is equal to the max product, choose the smaller element
            if num < element_to_remove:
                element_to_remove = num

    return element_to_remove

