def prime_primes(N):
    # Helper function to check if a number is prime
    def is_prime(num):
        if num <= 1:
            return False
        if num <= 3:
            return True
        if num % 2 == 0 or num % 3 == 0:
            return False
        i = 5
        while i * i <= num:
            if num % i == 0 or num % (i + 2) == 0:
                return False
            i += 6
        return True

    # Generate a list of prime numbers less than N
    primes = [i for i in range(2, N) if is_prime(i)]

    # Initialize count and sum of "prime primes"
    count = 0
    sum_of_prime_primes = 0.0

    # Iterate over pairs of primes to find "prime primes" less than 1
    for i in range(len(primes)):
        for j in range(i + 1, len(primes)):
            if primes[i] < primes[j]:
                count += 1
                sum_of_prime_primes += primes[i] / primes[j]

    # Return the count and the integer part of the sum
    return [count, int(sum_of_prime_primes)]

