def is_mersenne_prime(n):
    # Calculate the Mersenne number for the given n
    mersenne_number = (1 << n) - 1  # This is equivalent to 2^n - 1

    # Function to check if a number is prime
    def is_prime(num):
        if num <= 1:
            return False
        if num <= 3:
            return True
        if num % 2 == 0 or num % 3 == 0:
            return False
        i = 5
        while i * i <= num:
            if num % i == 0 or num % (i + 2) == 0:
                return False
            i += 6
        return True

    # Check if the Mersenne number is prime
    return is_prime(mersenne_number)

