def solve_expression(expression):
    import re

    # Split the expression into left and right parts
    left, right = expression.split('=')

    # Find the operator in the left part
    operator_match = re.search(r'[+\-*]', left)
    if not operator_match:
        return -1

    operator = operator_match.group()
    left_parts = left.split(operator)

    # Function to replace '?' with a digit and evaluate the expression
    def evaluate_with_digit(digit):
        if str(digit) in expression:
            return False  # The digit is already present in the expression

        # Replace '?' with the digit
        left_eval = left.replace('?', str(digit))
        right_eval = right.replace('?', str(digit))

        # Check for leading zeros
        if re.search(r'\b0\d', left_eval) or re.search(r'\b0\d', right_eval):
            return False

        # Evaluate the expression
        try:
            if operator == '+':
                result = int(left_parts[0].replace('?', str(digit))) + int(left_parts[1].replace('?', str(digit)))
            elif operator == '-':
                result = int(left_parts[0].replace('?', str(digit))) - int(left_parts[1].replace('?', str(digit)))
            elif operator == '*':
                result = int(left_parts[0].replace('?', str(digit))) * int(left_parts[1].replace('?', str(digit)))
            else:
                return False

            return result == int(right_eval)
        except ValueError:
            return False

    # Try each digit from 0 to 9
    for digit in range(10):
        if evaluate_with_digit(digit):
            return digit

    return -1

