def count_ways(n, k):
    # Helper function to find all factors of a number
    def get_factors(x):
        factors = []
        for i in range(1, int(x**0.5) + 1):
            if x % i == 0:
                factors.append(i)
                if i != x // i:
                    factors.append(x // i)
        return factors

    # Dynamic programming table to store the number of ways
    dp = [[0] * (k + 1) for _ in range(n + 1)]
    dp[1][0] = 1  # Base case: 1 way to multiply 0 numbers to get 1

    # Iterate over all numbers from 1 to n
    for num in range(1, n + 1):
        factors = get_factors(num)
        # Iterate over all possible number of factors (1 to k)
        for j in range(1, k + 1):
            # Sum up the ways to form the current number using j factors
            for factor in factors:
                if num % factor == 0:
                    dp[num][j] += dp[num // factor][j - 1]

    return dp[n][k]

