    # Function to calculate binomial coefficient C(n, k)
    def binomial(n, k):
        if k > n:
            return 0
        if k == 0 or k == n:
            return 1
        k = min(k, n - k)  # Take advantage of symmetry
        c = 1
        for i in range(k):
            c = c * (n - i) // (i + 1)
        return c

    # Calculate the total number of increasing numbers
    def count_increasing(digits):
        return binomial(digits + 9, 9) - 1  # Subtract 1 to exclude the number with all zeros

    # Calculate the total number of decreasing numbers
    def count_decreasing(digits):
        return binomial(digits + 10, 10) - (digits + 1)  # Subtract (digits + 1) to exclude leading zeros

    # Calculate the total number of flat numbers (e.g., 111, 222)
    def count_flat(digits):
        return 9 * digits

    if x == 0:
        return 1  # Only the number 0

    # Calculate the total number of increasing and decreasing numbers
    total = count_increasing(x) + count_decreasing(x) - count_flat(x)

    return total

