def count_paths(n, m, labyrinth):
    MOD = 10**9 + 7

    # Initialize dp array
    dp = [[0] * m for _ in range(n)]
    dp[0][0] = 1  # Starting point

    # Precompute the number of rocks to the right and below each cell
    right_rocks = [[0] * m for _ in range(n)]
    down_rocks = [[0] * m for _ in range(n)]

    for i in range(n):
        for j in range(m - 1, -1, -1):
            if j < m - 1:
                right_rocks[i][j] = right_rocks[i][j + 1]
            if labyrinth[i][j] == 'R':
                right_rocks[i][j] += 1

    for j in range(m):
        for i in range(n - 1, -1, -1):
            if i < n - 1:
                down_rocks[i][j] = down_rocks[i + 1][j]
            if labyrinth[i][j] == 'R':
                down_rocks[i][j] += 1

    # Calculate the number of paths using dynamic programming
    for i in range(n):
        for j in range(m):
            if i == 0 and j == 0:
                continue

            # Calculate paths coming from the left
            if j > 0:
                left_limit = j - right_rocks[i][j]
                if left_limit >= 0:
                    dp[i][j] = (dp[i][j] + dp[i][left_limit]) % MOD

            # Calculate paths coming from above
            if i > 0:
                up_limit = i - down_rocks[i][j]
                if up_limit >= 0:
                    dp[i][j] = (dp[i][j] + dp[up_limit][j]) % MOD

    return dp[n - 1][m - 1]

