def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    index = 0
    k = int(data[index])
    index += 1

    boxes = []
    total_sum = 0
    for i in range(k):
        n_i = int(data[index])
        index += 1
        a_i = list(map(int, data[index:index + n_i]))
        index += n_i
        boxes.append(a_i)
        total_sum += sum(a_i)

    # Check if total sum is divisible by k
    if total_sum % k != 0:
        print("No")
        return

    target_sum = total_sum // k

    # Map to store the sum of each box
    box_sums = [sum(box) for box in boxes]

    # Map to store the original index of each number
    num_to_box = {}
    for i in range(k):
        for num in boxes[i]:
            num_to_box[num] = i

    # Map to store the difference needed for each box to reach target_sum
    needed_diff = [target_sum - box_sums[i] for i in range(k)]

    # Map to store the solution
    solution = [-1] * k

    # Try to find a cycle of numbers that can balance the boxes
    visited = {}

    def find_cycle(start_box, start_num):
        current_box = start_box
        current_num = start_num
        cycle = []

        while True:
            cycle.append((current_num, current_box))
            visited[current_num] = True
            next_box = num_to_box[current_num]
            next_num = needed_diff[next_box] + current_num

            if next_num in visited:
                if next_num == start_num:
                    return cycle
                else:
                    return None

            if next_num not in num_to_box:
                return None

            current_box = next_box
            current_num = next_num

    for i in range(k):
        for num in boxes[i]:
            if num not in visited:
                cycle = find_cycle(i, num)
                if cycle:
                    for num, box in cycle:
                        solution[box] = (num, num_to_box[num] + 1)

    if -1 in solution:
        print("No")
    else:
        print("Yes")
        for num, box in solution:
            print(num, box)

