def solve_parking_lot(n, k, grid):
    moves = []
    max_moves = 20000

    def move_car(car, r, c):
        moves.append((car, r, c))
        grid[r][c] = car

    def is_solved():
        for c in range(n):
            if grid[0][c] != 0 and grid[0][c] != grid[1][c]:
                return False
            if grid[3][c] != 0 and grid[3][c] != grid[2][c]:
                return False
        return True

    def try_to_park():
        for c in range(n):
            if grid[1][c] != 0 and grid[0][c] == grid[1][c]:
                move_car(grid[1][c], 0, c)
                grid[1][c] = 0
            if grid[2][c] != 0 and grid[3][c] == grid[2][c]:
                move_car(grid[2][c], 3, c)
                grid[2][c] = 0

    def find_empty():
        for r in range(1, 3):
            for c in range(n):
                if grid[r][c] == 0:
                    return r, c
        return None

    def move_to_empty(r, c, er, ec):
        if r == er:
            if c < ec:
                for i in range(c, ec):
                    move_car(grid[r][i + 1], r, i)
                    grid[r][i] = grid[r][i + 1]
                    grid[r][i + 1] = 0
            else:
                for i in range(c, ec, -1):
                    move_car(grid[r][i - 1], r, i)
                    grid[r][i] = grid[r][i - 1]
                    grid[r][i - 1] = 0
        else:
            if r == 1:
                move_car(grid[1][c], 2, c)
                grid[2][c] = grid[1][c]
                grid[1][c] = 0
                move_to_empty(2, c, er, ec)
            else:
                move_car(grid[2][c], 1, c)
                grid[1][c] = grid[2][c]
                grid[2][c] = 0
                move_to_empty(1, c, er, ec)

    while not is_solved() and len(moves) < max_moves:
        try_to_park()
        empty = find_empty()
        if not empty:
            break
        er, ec = empty
        for r in range(1, 3):
            for c in range(n):
                if grid[r][c] != 0:
                    if (r == 1 and grid[0][c] == grid[r][c]) or (r == 2 and grid[3][c] == grid[r][c]):
                        continue
                    move_to_empty(r, c, er, ec)
                    break
            else:
                continue
            break

    if is_solved():
        print(len(moves))
        for move in moves:
            print(move[0], move[1] + 1, move[2] + 1)
    else:
        print(-1)

