def lucky_permutation(n):
    if n == 1:
        return [1]
    if n % 2 == 1:
        return -1
    else:
        # Create a permutation where p[i] = i + 1 for odd i and p[i] = i - 1 for even i
        permutation = [0] * n
        for i in range(1, n + 1):
            if i % 2 == 1:
                permutation[i - 1] = i + 1
            else:
                permutation[i - 1] = i - 1
        return permutation

